        for (let i = 0; i < H * W; i++) {
            if (allChars[i] === 'S') {
                startR = Math.floor(i / W);
                startC = i % W;
                break;
            }
        }

        if (startR === -1) {
            // This case shouldn't happen based on the problem description
            return;
        }

        const dist = new Float64Array(H * W).fill(Infinity);
        const pq = new MinHeap<[number, number]>();

        dist[startR * W + startC] = 0;
        pq.push([startR, startC], 0);

        const dr = [-1, 1, 0, 0];
        const dc = [0, 0, -1, 1];

        while (pq.size() > 0) {
            const item = pq.pop();
            if (!item) break;
            const { val, priority: d } = item;
            const [r, c] = val;

            if (d > dist[r * W + c]) continue;
            if (allChars[r * W + c] === 'T') {
                process.stdout.write(d.toString() + "\n");
                return;
            }

            for (let i = 0; i < 4; i++) {
                const nr = r + dr[i];
                const nc = c + dc[i];

                if (nr >= 0 && nr < H && nc >= 0 && nc < W) {
                    const idx = nr * W + nc;
                    const char = allChars[idx];
                    if (char !== '#') {
                        let moveCost = 0;
                        if (char >= '0' && char <= '9') {
                            moveCost = char.charCodeAt(0) - 48;
                        }

                        const newDist = d + moveCost;
                        if (newDist < dist[idx]) {
                            dist[idx] = newDist;
                            pq.push([nr, nc], newDist);
                        }
                    }
                }
            }
        }

        process.stdout.write("-1\n");
    }

    solve();
    ```

    *   The input `H W` and then `H` lines of `W` characters.
    *   The `allChars = input.slice(2).join("")` approach is robust as long as the grid characters themselves are not whitespace.
    *   If $H=1000, W=1000$, `allChars` is $1,000,000$ characters. `input.slice(2)` could be $1,000,000$ strings if every character is separated by a space. This is the most extreme case. Node.js can handle this, but it's something to keep in mind.
    *   The time complexity is fine.
    *   The space complexity is fine.

    One small thing: `process.stdout.write(d.toString() + "\n");` is better than `console.log` for large outputs, though here we only output once.
